import React from 'react';

const Account = () => {
  return (
    <div className="p-4">
      <h1 className="text-2xl font-bold mb-2">Account Page</h1>
      <p>Welcome to your account. Here you can view and manage your virtual ID.</p>
    </div>
  );
};

export default Account;
